import { Box, Typography } from '@mui/material';
import { getFormattedDate } from '@utils/dateUtils';
import React from 'react';
import { useNavigate } from 'react-router-dom';

import styles from '../BlogPage.module.css';

const BlogListPost = ({ shouldRender, slug, post, index, handleTagClick }) => {
  const { date, image, title, excerpt, tags, type, readingTime } = post;
  const formattedDate = getFormattedDate(date);
  const isClickablePost = type === 'post';
  const navigate = useNavigate();

  const handleClick = (e) => {
    if (e.button === 2 || e.ctrlKey || e.metaKey) return;
    e.preventDefault();
    navigate(`/blog/${slug}`);
  };

  const linkProps = isClickablePost
    ? {
        href: `/blog/${slug}`,
        onClick: handleClick,
        style: {
          cursor: 'pointer',
          textDecoration: 'none',
          color: 'inherit',
        },
      }
    : {
        style: {
          cursor: 'default',
          textDecoration: 'none',
          color: 'inherit',
        },
      };

  const dateLinkProps = {
    ...linkProps,
    style: {
      ...linkProps.style,
      color: '#ce0000',
      textDecoration: 'none',
    },
  };

  return (
    <Box
      key={index}
      className={styles.blogListPost}
      sx={{
        textDecoration: 'none',
        color: 'inherit',
        opacity: shouldRender ? 1 : 0,
      }}
    >
      <a {...linkProps}>
        <img
          src={require(`@content/blog/images/${image}`)}
          alt={title}
          className={styles.blogListPostImage}
          style={{ cursor: isClickablePost ? 'pointer' : 'default' }}
        />
      </a>

      <Box className={styles.blogListPostTitle}>
        <Typography variant="h3" className={styles.blogListPostTitleText}>
          <a {...dateLinkProps} className={styles.postDate}>
            {formattedDate}
          </a>
          <a {...linkProps}>{title}</a>
        </Typography>
      </Box>

      <Box className={styles.blogListPostDivider} />

      {tags?.length > 0 && (
        <Box className={styles.postTags}>
          {tags.map((tag, i) => (
            <React.Fragment key={tag}>
              <Typography
                component="span"
                variant="body2"
                className={styles.postTag}
                onClick={() => handleTagClick(tag)}
              >
                {tag}
              </Typography>
              {i < tags.length - 1 && ', '}
            </React.Fragment>
          ))}
        </Box>
      )}

      <Typography variant="body2" sx={{ marginBottom: '0.5rem' }}>
        <a {...linkProps}>{excerpt}</a>
      </Typography>

      {readingTime && (
        <Typography variant="body2" sx={{ fontStyle: 'italic' }}>
          {readingTime} min read
        </Typography>
      )}
    </Box>
  );
};

export default BlogListPost;
