import metadata from '@content/blog/metadata';
import { Box, Chip, Typography } from '@mui/material';
import { compareDate } from '@utils/dateUtils';

import styles from '../BlogPage.module.css';
import BlogListPost from './BlogListPost';

const BlogList = ({
  isResizing,
  visiblePosts,
  displayCount,
  handleLoadMore,
  activeTags,
  handleTagClick,
  filteredPosts,
}) => {
  return (
    <Box
      className={styles.blogListContainer}
      sx={{
        opacity: isResizing ? 0 : 1,
      }}
    >
      <Typography variant="h3" sx={{ mb: 1 }}>
        ~ Explore ~
      </Typography>
      {activeTags.length > 0 ? (
        <Box sx={{ mb: 2 }}>
          <Box
            sx={{
              display: 'flex',
              alignItems: 'center',
              gap: 1,
              flexWrap: 'wrap',
            }}
          >
            <Typography variant="h6">Filtering to Tags:</Typography>
            {activeTags.map((tag) => (
              <Chip
                key={tag}
                label={tag}
                onDelete={() => handleTagClick(tag)}
                color="primary"
                size="small"
              />
            ))}
          </Box>
        </Box>
      ) : (
        <Typography variant="h6" sx={{ mb: 2 }}>
          ~ Wander Through and Read Awhile ~
        </Typography>
      )}
      <Box
        className={styles.blogListPostsContainer}
        sx={{
          gridTemplateColumns: {
            xs: '1fr',
            sm: 'repeat(2, 1fr)',
            md: 'repeat(3, 1fr)',
          },
        }}
      >
        {filteredPosts.slice(0, displayCount).map(([slug, post], index) => (
          <BlogListPost
            key={index}
            shouldRender={visiblePosts.includes(index)}
            slug={slug}
            post={post}
            index={index}
            handleTagClick={handleTagClick}
          />
        ))}
      </Box>

      {displayCount < filteredPosts.length ? (
        <Typography
          onClick={handleLoadMore}
          variant="h3"
          sx={{
            mt: 4,
            mb: 2,
            cursor: 'pointer',
            '&:hover': {
              color: 'grey',
            },
          }}
        >
          Load More
        </Typography>
      ) : (
        <Box className={styles.blogListFin}>
          <Typography sx={{ fontStyle: 'italic' }}>~ Fin. ~</Typography>
        </Box>
      )}
    </Box>
  );
};

export default BlogList;
