import Footer from '@components/Footer/Footer';
import Navbar from '@components/Navbar/Navbar';
import { MobileContext } from '@contexts/MobileContext';
import useIsResizing from '@hooks/useIsResizing';
import FlareIcon from '@mui/icons-material/Flare';
import { Box, Typography } from '@mui/material';
import commonStyles from '@styles/common.module.css';
import React, { useContext, useEffect, useRef, useState } from 'react';
import { useSelector } from 'react-redux';

import styles from './AboutPage.module.css';
import TypewriterText from './components/TypewriterText';

const aboutText = `
  Steinbeck Enthusiast. Sunset connoisseur. Engineer by trade. New Yorker by blood.
  Stargazing, daydreaming. I write, on occasion.
`;

const welcomeText = 'Welcome to the garden. Come, stay a while.';

const shiftCharacter = (char, n) => {
  if (!/[a-zA-Z]/.test(char)) return char;
  const isUpperCase = char === char.toUpperCase();
  const base = isUpperCase ? 'A'.charCodeAt(0) : 'a'.charCodeAt(0);
  const shifted = ((char.toLowerCase().charCodeAt(0) - base + n) % 26) + base;
  const shiftedChar = String.fromCharCode(shifted);
  return isUpperCase ? shiftedChar.toUpperCase() : shiftedChar;
};

const AboutPage = () => {
  const isResizing = useIsResizing();
  const isMobile = useContext(MobileContext);
  const isDarkMode = useSelector((state) => state.theme.isDarkMode);
  const [shiftedText, setShiftedText] = useState(
    aboutText
      .split('')
      .map((char) => shiftCharacter(char, 1))
      .join('')
  );
  const [isTextShifted, setIsTextShifted] = useState(false);
  const [isShifting, setIsShifting] = useState(false);
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    const timer = setTimeout(() => {
      setIsVisible(true);
    }, 100);
    return () => clearTimeout(timer);
  }, []);

  const shiftText = async (n) => {
    if (isTextShifted || isShifting) return;
    setIsShifting(true);
    for (let i = 0; i < n; i++) {
      await new Promise((resolve) => setTimeout(resolve, calculateTimeout(i)));
      setShiftedText((prev) =>
        prev
          .split('')
          .map((char) => shiftCharacter(char, 1))
          .join('')
      );
    }
    setIsShifting(false);
    setIsTextShifted(true);
  };

  const calculateTimeout = (i) => {
    return 500 * Math.exp(-0.2 * i);
  };

  return (
    <Box className={commonStyles.pageLayout}>
      <Navbar />
      <Box
        className={
          isMobile ? styles.mobileAboutPageContainer : styles.aboutPageContainer
        }
        sx={{
          opacity: isResizing ? 0 : 1,
          transition: 'opacity 0.15s ease-out',
        }}
      >
        <Box
          className={styles.aboutPageContent}
          sx={{
            flexDirection: isMobile ? 'column' : 'row',
            opacity: isVisible ? 1 : 0,
            transform: isVisible ? 'translateY(0)' : 'translateY(20px)',
            transition: 'opacity 0.6s ease-out, transform 0.6s ease-out',
          }}
        >
          <Box
            className={styles.aboutPageContentImageContainer}
            sx={{
              width: isMobile ? '100%' : '45%',
            }}
          >
            <img
              className={styles.aboutPageImage}
              src={require('@assets/eyw.webp')}
              alt="About"
            />
          </Box>
          <Box
            className={styles.aboutPageContentBodyContainer}
            sx={{
              width: isMobile ? '100%' : '55%',
              ...(!isMobile && {
                marginLeft: '2rem',
              }),
              ...(isMobile && {
                marginTop: '2rem',
              }),
            }}
          >
            <Typography
              variant="h1"
              sx={{ fontSize: '2rem', marginBottom: '1rem' }}
            >
              eden west
              <FlareIcon
                className={
                  isShifting || isTextShifted
                    ? undefined
                    : isDarkMode
                      ? styles.aboutPageIconDark
                      : styles.aboutPageIcon
                }
                onClick={(e) => {
                  if (isShifting || isTextShifted) return;
                  e.target.style.transform = 'rotate(720deg)';
                  e.target.style.transition =
                    'transform 0.5s cubic-bezier(0.68, -0.55, 0.265, 1.55)';
                  shiftText(103);
                }}
                sx={{
                  fontSize: '1.5rem',
                  marginLeft: '0.75rem',
                }}
              />
            </Typography>
            <Typography variant="body1" sx={{ height: '150px' }}>
              {shiftedText}
              {isTextShifted && !isShifting && <br />}
              {isTextShifted && !isShifting && <br />}
              <TypewriterText
                isVisible={isTextShifted && !isShifting}
                duration={3500}
                text={welcomeText}
              />
            </Typography>
          </Box>
        </Box>
      </Box>
      <Footer />
    </Box>
  );
};

export default AboutPage;
