import NightlightIcon from '@mui/icons-material/Nightlight';
import WbSunnyIcon from '@mui/icons-material/WbSunny';
import { Box, Button, Typography } from '@mui/material';
import { IconButton } from '@mui/material';
import { toggleTheme } from '@redux/slices/themeSlice';
import commonStyles from '@styles/common.module.css';
import React from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';

import styles from './LandingPage.module.css';

const LandingPage = () => {
  const navigate = useNavigate();
  const dispatch = useDispatch();
  const isDarkMode = useSelector((state) => state.theme.isDarkMode);

  const renderThemeToggle = () => (
    <IconButton
      color="inherit"
      aria-label="theme-toggle"
      onClick={() => dispatch(toggleTheme())}
    >
      {isDarkMode ? <WbSunnyIcon /> : <NightlightIcon />}
    </IconButton>
  );

  return (
    <>
      <Box className={commonStyles.pageLayout}>
        <Box className={styles.landingContainer}>
          <Box className={styles.landingContent}>
            <Typography variant="h1" sx={{ marginBottom: '0.75rem' }}>
              EdenIncorporated
            </Typography>
            <Box className={styles.landingSubtitleContainer}>
              <Typography
                variant="h4"
                sx={{ marginBottom: '0.75rem', fontWeight: 400 }}
              >
                explore, with wonder. a blog, by eden west.
              </Typography>
            </Box>
            <Box className={styles.landingButtonContainer}>
              <Button variant="mono" onClick={() => navigate('/blog')}>
                Blog
              </Button>
              <Button variant="mono" onClick={() => navigate('/gallery')}>
                Gallery
              </Button>
              {/* TODO: Add Timshel */}
              {/* <Button variant="mono" onClick={() => navigate('/timshel')}>
                Timshel
              </Button> */}
              <Button variant="mono" onClick={() => navigate('/about')}>
                About
              </Button>
              {renderThemeToggle()}
            </Box>
          </Box>
        </Box>
      </Box>
    </>
  );
};

export default LandingPage;
