import Footer from '@components/Footer/Footer';
import Navbar from '@components/Navbar/Navbar';
import metadata from '@content/blog/metadata';
import { MobileContext } from '@contexts/MobileContext';
import useIsResizing from '@hooks/useIsResizing';
import { Box } from '@mui/material';
import commonStyles from '@styles/common.module.css';
import React, { useContext, useEffect, useState } from 'react';
import { useSearchParams } from 'react-router-dom';

import styles from './BlogPage.module.css';
import BlogList from './components/BlogList';
import FeaturedPosts from './components/FeaturedPosts';

const BlogPage = () => {
  const isResizing = useIsResizing();
  const [filteredPosts, setFilteredPosts] = useState([]);
  const [visiblePosts, setVisiblePosts] = useState([]);
  const [activeTags, setActiveTags] = useState([]);
  const [displayCount, setDisplayCount] = useState(9);
  const [previousDisplayCount, setPreviousDisplayCount] = useState(0);
  const [searchParams, setSearchParams] = useSearchParams();
  const isMobile = useContext(MobileContext);

  useEffect(() => {
    const tagsParam = searchParams.get('tags');
    if (tagsParam) {
      const tags = tagsParam.split(',');
      setActiveTags(tags);
    }
  }, []);

  const getActivePosts = () => {
    let sortedPosts = Object.entries(metadata).sort(
      (a, b) => new Date(b[1].date) - new Date(a[1].date)
    );
    if (activeTags.length > 0) {
      sortedPosts = sortedPosts.filter(
        ([_, post]) =>
          post.tags?.length > 0 &&
          activeTags.every((tag) => post.tags.includes(tag))
      );
    }
    return sortedPosts;
  };

  const updateActiveTags = (tag) => {
    setActiveTags((prev) => {
      const newTags = prev.includes(tag)
        ? prev.filter((t) => t !== tag)
        : [...prev, tag];

      if (newTags.length > 0) {
        setSearchParams({ tags: newTags.join(',') });
      } else {
        setSearchParams({});
      }

      return newTags;
    });
  };

  useEffect(() => {
    const sortedPosts = getActivePosts();
    setFilteredPosts(sortedPosts);

    const showPostsSequentially = async () => {
      for (
        let i = previousDisplayCount;
        i < Math.min(displayCount, sortedPosts.length);
        i++
      ) {
        await new Promise((resolve) => setTimeout(resolve, 200));
        setVisiblePosts((prev) => [...prev, i]);
      }
    };

    showPostsSequentially();
  }, [displayCount]);

  useEffect(() => {
    const sortedPosts = getActivePosts();
    setFilteredPosts(sortedPosts);

    const showPostsSequentially = async () => {
      for (let i = 0; i < Math.min(displayCount, sortedPosts.length); i++) {
        await new Promise((resolve) => setTimeout(resolve, 200));
        setVisiblePosts((prev) => [...prev, i]);
      }
    };

    setTimeout(() => {
      showPostsSequentially();
    }, 50);
  }, [activeTags]);

  const handleLoadMore = () => {
    setPreviousDisplayCount(displayCount);
    setDisplayCount((prev) => prev + 9);
  };

  const handleTagClick = (tag) => {
    setVisiblePosts([]);
    setFilteredPosts([]);
    updateActiveTags(tag);
    setDisplayCount(9);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <Box className={commonStyles.pageLayout}>
      <Navbar />
      <Box
        className={
          isMobile ? styles.blogPageContentMobile : styles.blogPageContent
        }
      >
        <FeaturedPosts
          isResizing={isResizing}
          handleTagClick={handleTagClick}
          activeTags={activeTags}
        />
        <BlogList
          isResizing={isResizing}
          visiblePosts={visiblePosts}
          displayCount={displayCount}
          handleLoadMore={handleLoadMore}
          activeTags={activeTags}
          handleTagClick={handleTagClick}
          filteredPosts={filteredPosts}
        />
      </Box>
      <Footer />
    </Box>
  );
};

export default BlogPage;
