import metadata from '@content/blog/metadata';
import { MobileContext } from '@contexts/MobileContext';
import ArrowBackIosNewIcon from '@mui/icons-material/ArrowBackIosNew';
import ArrowForwardIosIcon from '@mui/icons-material/ArrowForwardIos';
import { Box, Typography } from '@mui/material';
import { compareDate, getFullDate } from '@utils/dateUtils';
import React, { useContext, useEffect, useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';

import styles from '../BlogPage.module.css';

const ROTATION_INTERVAL = 5000;

const FeaturedPosts = ({ isResizing, handleTagClick, activeTags }) => {
  const [activeIndex, setActiveIndex] = useState(0);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [isInitialLoad, setIsInitialLoad] = useState(true);
  const timerRef = useRef(null);
  const navigate = useNavigate();
  const isMobile = useContext(MobileContext);

  const sortedPosts = Object.entries(metadata).sort(compareDate);
  const featuredPosts = sortedPosts.filter((post) => post[1].featured === true);

  const handleClick = (e) => {
    if (e.button === 2 || e.ctrlKey || e.metaKey) return;
    e.preventDefault();
    navigate(`/blog/${slug}`);
  };

  const startRotationTimer = () => {
    if (timerRef.current) {
      clearInterval(timerRef.current);
    }

    timerRef.current = setInterval(() => {
      setIsTransitioning(true);
      setTimeout(() => {
        setActiveIndex((prev) => (prev + 1) % featuredPosts.length);
        setIsTransitioning(false);
      }, 300);
    }, ROTATION_INTERVAL);
  };

  useEffect(() => {
    return () => {
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    };
  }, []);

  useEffect(() => {
    setTimeout(() => {
      setIsInitialLoad(false);
    }, 100);

    startRotationTimer();
  }, [featuredPosts.length]);

  useEffect(() => {
    if (!isResizing) {
      startRotationTimer();
    }
  }, [isResizing]);

  const handleBreadcrumbClick = (index) => {
    if (index === activeIndex) return;
    setIsTransitioning(true);
    setTimeout(() => {
      setActiveIndex(index);
      setIsTransitioning(false);
      startRotationTimer();
    }, 300);
  };

  if (featuredPosts.length === 0 || activeTags.length > 0) return null;

  const currentPost = featuredPosts[activeIndex];
  const [slug, post] = currentPost;
  const formattedDate = getFullDate(post.date);

  const linkProps = {
    href: `/blog/${slug}`,
    onClick: handleClick,
    style: {
      cursor: 'pointer',
      textDecoration: 'none',
      color: 'inherit',
    },
  };

  const dateLinkProps = {
    ...linkProps,
    style: {
      ...linkProps.style,
      color: '#ce0000',
      textDecoration: 'none',
    },
  };

  const renderFeaturedPostImage = () => {
    if (isMobile) {
      return (
        <Box
          className={styles.featuredPostMobileImageContainer}
          sx={{
            width: isMobile ? '100%' : '35%',
            opacity: isTransitioning ? 0 : 1,
          }}
        >
          <Box
            className={styles.featuredPostMobileImageArrow}
            onClick={() =>
              handleBreadcrumbClick(
                (activeIndex - 1 + featuredPosts.length) % featuredPosts.length
              )
            }
          >
            <ArrowBackIosNewIcon />
          </Box>
          <a
            href={`/blog/${slug}`}
            onClick={handleClick}
            className={styles.featuredPostImage}
          >
            <img
              src={require(`@content/blog/images/${post.image}`)}
              alt={post.title}
              style={{ width: '100%', height: '100%', objectFit: 'contain' }}
            />
          </a>
          <Box
            className={styles.featuredPostMobileImageArrow}
            onClick={() =>
              handleBreadcrumbClick((activeIndex + 1) % featuredPosts.length)
            }
          >
            <ArrowForwardIosIcon />
          </Box>
        </Box>
      );
    }
    return (
      <a
        href={`/blog/${slug}`}
        onClick={handleClick}
        className={styles.featuredPostImage}
        style={{
          opacity: isTransitioning ? 0 : 1,
          width: isMobile ? '100%' : '45%',
          height: isMobile ? '40%' : '100%',
        }}
      >
        <img
          src={require(`@content/blog/images/${post.image}`)}
          alt={post.title}
          style={{ width: '100%', height: '100%', objectFit: 'contain' }}
        />
      </a>
    );
  };

  const renderFeaturedPostContent = () => {
    return (
      <Box
        className={styles.featuredPostContent}
        sx={{
          flexDirection: isMobile ? 'column' : 'row',
          height: isMobile ? 'auto' : '50vh',
          minHeight: isMobile ? '60vh' : '50vh',
        }}
      >
        {renderFeaturedPostImage()}
        <Box
          className={styles.featuredPostText}
          sx={{
            opacity: isTransitioning ? 0 : 1,
            width: isMobile ? '90%' : '55%',
          }}
        >
          <Typography variant="h3" sx={{ marginBottom: '0.5rem' }}>
            <a {...dateLinkProps} className={styles.postDate}>
              {formattedDate}
            </a>
            <a {...linkProps}>{post.title}</a>
          </Typography>
          {post.tags.map((tag, i) => (
            <React.Fragment key={tag}>
              <Typography
                component="span"
                variant="body2"
                className={styles.postTag}
                onClick={() => handleTagClick(tag)}
                sx={{ marginBottom: '0.5rem' }}
              >
                {tag}
              </Typography>
              {i < post.tags.length - 1 && ', '}
            </React.Fragment>
          ))}
          <Typography variant="body2" sx={{ marginBottom: '0.5rem' }}>
            <a {...linkProps}>{post.excerpt}</a>
          </Typography>

          {post.readingTime && (
            <Typography variant="body2" sx={{ fontStyle: 'italic' }}>
              <a {...linkProps}>{post.readingTime} min read</a>
            </Typography>
          )}
        </Box>
      </Box>
    );
  };

  return (
    <Box
      className={styles.featuredPostContainer}
      sx={{ opacity: isResizing || isInitialLoad ? 0 : 1 }}
    >
      <Typography variant="h3" sx={{ mb: 1 }}>
        ~ Featured ~
      </Typography>
      <Typography variant="h6" sx={{ mb: 2 }}>
        ~ Highlights, Curated from the Hourglass ~
      </Typography>

      {renderFeaturedPostContent()}
      <Box className={styles.featuredPostBottomContainer}>
        {featuredPosts.map((_, index) => (
          <Box
            key={index}
            onClick={() => handleBreadcrumbClick(index)}
            className={styles.featuredPostBreadcrumb}
            sx={{
              backgroundColor: index === activeIndex ? '#ce0000' : '#ccc',
            }}
          />
        ))}
      </Box>
    </Box>
  );
};

export default FeaturedPosts;
